const messages = $items().map(item => {
  let msg = item.json.message;

  // Ensure message is an object
  if (typeof msg === 'string') {
    try {
      msg = JSON.parse(msg);
    } catch (err) {
      throw new Error(`Failed to parse message: ${msg}`);
    }
  }

  let role = msg.type === 'ai' ? '🤖 Chatbot' : '🧑 Usuário';
  let content = msg.content;

  // Some human messages have JSON-encoded content (timestamp + message)
  if (typeof content === 'string' && content.trim().startsWith('{')) {
    try {
      const inner = JSON.parse(content);
      if (inner.message) {
        content = inner.message;
      }
    } catch (e) {
      // keep as-is if not valid JSON
    }
  }

  // Ignorar comando ##delete
  if (content === '##delete') return null;

  return `${role}: ${content}`;
}).filter(Boolean); // remove nulls

const formatted = messages.join('<br>');

return [
  {
    json: {
      session_id: $("inicio_fluxo").last().json.session_id,
      conversation_text: formatted
    }
  }
];

